/**
 * Normalize a PulseBoard messaging target (username or board name).
 *
 * Usernames are lowercase alphanumeric with optional hyphens/underscores.
 * Board names are prefixed with "#" (e.g. "#general").
 */
export function normalizePulseboardTarget(target: string): string {
  const trimmed = target.trim();
  if (!trimmed) {
    return "";
  }
  // Board targets start with "#"
  if (trimmed.startsWith("#")) {
    return `#${trimmed.slice(1).toLowerCase().trim()}`;
  }
  // Username targets are lowercased
  return trimmed.toLowerCase();
}

/**
 * Check whether a target looks like a PulseBoard board (group) vs a DM target.
 */
export function isBoardTarget(target: string): boolean {
  return target.trim().startsWith("#");
}

/**
 * Check whether input looks like a PulseBoard target identifier.
 * Accepts usernames (alphanumeric + hyphens/underscores) or board names (#name).
 */
export function looksLikePulseboardTargetId(input: string): boolean {
  const trimmed = input.trim();
  if (!trimmed) {
    return false;
  }
  if (trimmed.startsWith("#")) {
    return /^#[a-zA-Z0-9_-]+$/.test(trimmed);
  }
  return /^[a-zA-Z0-9_-]+$/.test(trimmed);
}

/**
 * Normalize an allow-from entry (username).
 * Returns null for invalid entries, "*" for wildcard.
 */
export function normalizePulseboardAllowEntry(entry: string): string | "*" | null {
  const trimmed = entry.trim().toLowerCase();
  if (!trimmed) {
    return null;
  }
  if (trimmed === "*") {
    return "*";
  }
  if (/^[a-zA-Z0-9_-]+$/.test(trimmed)) {
    return trimmed;
  }
  return null;
}

