/**
 * Placeholder PulseBoard message delivery.
 *
 * In a real implementation this would call the PulseBoard HTTP/WebSocket API.
 * The stub logs the attempt and returns a synthetic message ID so the rest
 * of the plugin pipeline can be exercised end-to-end.
 */
export async function sendPulseboardMessage(opts: {
  serverUrl: string;
  apiToken: string;
  to: string;
  text: string;
}): Promise<{ messageId: string }> {
  const { to, text } = opts;

  if (isBoardTarget(to)) {
    // Board (group) message delivery
    return { messageId: `pb-board-${Date.now()}` };
  }

  // Direct message delivery
  if (!text.trim()) {
    return { messageId: `pb-dm-empty-${Date.now()}` };
  }

  return { messageId: `pb-dm-${Date.now()}` };
}

