51	/** List normalized configured account ids from a raw channel account record map. */
52	export function listConfiguredAccountIds(params: {
53	  accounts: Record<string, unknown> | undefined;
54	  normalizeAccountId: (accountId: string) => string;
55	}): string[] {
56	  if (!params.accounts) {
57	    return [];
58	  }
59	  const ids = new Set<string>();
60	  for (const key of Object.keys(params.accounts)) {
61	    if (!key) {
62	      continue;
63	    }
64	    ids.add(params.normalizeAccountId(key));
65	  }
66	  return [...ids];
67	}
