70	    params.cfg,
71	  );
72	  const senderAllowedForCommands = params.isSenderAllowed(
73	    params.senderId,
74	    access.effectiveAllowFrom,
75	  );
76	  const commandAuthorized = shouldComputeAuth
77	    ? dmPolicy === "open"
78	      ? true
79	      : params.runtime.resolveCommandAuthorizedFromAuthorizers({
80	          useAccessGroups: params.cfg.commands?.useAccessGroups !== false,
81	          authorizers: [
82	            {
83	              configured: access.effectiveAllowFrom.length > 0,
84	              allowed: senderAllowedForCommands,
85	            },
86	          ],
87	          modeWhenAccessGroupsOff: params.modeWhenAccessGroupsOff,
88	        })
89	    : undefined;
90	
91	  return {
92	    access: {
93	      decision: access.decision,
94	      reasonCode: access.reasonCode,
95	      reason: access.reason,
96	      effectiveAllowFrom: access.effectiveAllowFrom,
97	    },
98	    shouldComputeAuth,
99	    senderAllowedForCommands,
100	    commandAuthorized,
101	  };
102	}
103	
104	/** Convert resolved DM policy into a pre-crypto allow/block/pairing callback. */
105	export function createPreCryptoDirectDmAuthorizer(params: {
106	  resolveAccess: (
107	    senderId: string,
108	  ) => Promise<Pick<ResolvedInboundDirectDmAccess, "access"> | ResolvedInboundDirectDmAccess>;
109	  issuePairingChallenge?: (params: {
110	    senderId: string;
111	    reply: (text: string) => Promise<void>;
112	  }) => Promise<void>;
113	  onBlocked?: (params: {
114	    senderId: string;
115	    reason: string;
116	    reasonCode: DmGroupAccessReasonCode;
117	  }) => void;
118	}) {
119	  return async (input: {
120	    senderId: string;
121	    reply: (text: string) => Promise<void>;
122	  }): Promise<"allow" | "block" | "pairing"> => {
123	    const resolved = await params.resolveAccess(input.senderId);
124	    const access = "access" in resolved ? resolved.access : resolved;
125	    if (access.decision === "allow") {
126	      return "allow";
127	    }
128	    if (access.decision === "pairing") {
129	      if (params.issuePairingChallenge) {
130	        await params.issuePairingChallenge({
131	          senderId: input.senderId,
132	          reply: input.reply,
133	        });
134	      }
135	      return "pairing";
136	    }
137	    params.onBlocked?.({
138	      senderId: input.senderId,
139	      reason: access.reason,
140	      reasonCode: access.reasonCode,
141	    });
142	    return "block";
143	  };
144	}
