146	export type DirectDmPreCryptoGuardPolicy = {
147	  allowedKinds: readonly number[];
148	  maxFutureSkewSec: number;
149	  maxCiphertextBytes: number;
150	  maxPlaintextBytes: number;
151	  rateLimit: {
152	    windowMs: number;
153	    maxPerSenderPerWindow: number;
154	    maxGlobalPerWindow: number;
155	    maxTrackedSenderKeys: number;
156	  };
157	};
158	
159	export type DirectDmPreCryptoGuardPolicyOverrides = Partial<
160	  Omit<DirectDmPreCryptoGuardPolicy, "rateLimit">
161	> & {
162	  rateLimit?: Partial<DirectDmPreCryptoGuardPolicy["rateLimit"]>;
163	};
164	
165	/** Shared policy object for DM-style pre-crypto guardrails. */
166	export function createDirectDmPreCryptoGuardPolicy(
167	  overrides: DirectDmPreCryptoGuardPolicyOverrides = {},
168	): DirectDmPreCryptoGuardPolicy {
169	  return {
170	    allowedKinds: overrides.allowedKinds ?? [4],
171	    maxFutureSkewSec: overrides.maxFutureSkewSec ?? 120,
172	    maxCiphertextBytes: overrides.maxCiphertextBytes ?? 16 * 1024,
173	    maxPlaintextBytes: overrides.maxPlaintextBytes ?? 8 * 1024,
174	    rateLimit: {
175	      windowMs: overrides.rateLimit?.windowMs ?? 60_000,
176	      maxPerSenderPerWindow: overrides.rateLimit?.maxPerSenderPerWindow ?? 20,
177	      maxGlobalPerWindow: overrides.rateLimit?.maxGlobalPerWindow ?? 200,
178	      maxTrackedSenderKeys: overrides.rateLimit?.maxTrackedSenderKeys ?? 4096,
179	    },
180	  };
181	}
