183	type DirectDmRoutePeer = {
184	  kind: "direct";
185	  id: string;
186	};
187	
188	type DirectDmRoute = {
189	  agentId: string;
190	  sessionKey: string;
191	  accountId?: string;
192	};
193	
194	type DirectDmRuntime = {
195	  channel: {
196	    routing: {
197	      resolveAgentRoute: (params: {
198	        cfg: OpenClawConfig;
199	        channel: string;
200	        accountId: string;
201	        peer: DirectDmRoutePeer;
202	      }) => DirectDmRoute;
203	    };
204	    session: {
205	      resolveStorePath: typeof import("../config/sessions.js").resolveStorePath;
206	      readSessionUpdatedAt: (params: {
207	        storePath: string;
208	        sessionKey: string;
209	      }) => number | undefined;
210	      recordInboundSession: typeof import("../channels/session.js").recordInboundSession;
211	    };
212	    reply: {
213	      resolveEnvelopeFormatOptions: (
214	        cfg: OpenClawConfig,
215	      ) => ReturnType<typeof import("../auto-reply/envelope.js").resolveEnvelopeFormatOptions>;
216	      formatAgentEnvelope: typeof import("../auto-reply/envelope.js").formatAgentEnvelope;
217	      finalizeInboundContext: typeof import("../auto-reply/reply/inbound-context.js").finalizeInboundContext;
218	      dispatchReplyWithBufferedBlockDispatcher: typeof import("../auto-reply/reply/provider-dispatcher.js").dispatchReplyWithBufferedBlockDispatcher;
219	    };
220	  };
221	};
222	
223	/** Route, envelope, record, and dispatch one direct-DM turn through the standard pipeline. */
224	export async function dispatchInboundDirectDmWithRuntime(params: {
225	  cfg: OpenClawConfig;
226	  runtime: DirectDmRuntime;
227	  channel: string;
228	  channelLabel: string;
229	  accountId: string;
230	  peer: DirectDmRoutePeer;
231	  senderId: string;
232	  senderAddress: string;
233	  recipientAddress: string;
234	  conversationLabel: string;
235	  rawBody: string;
236	  messageId: string;
237	  timestamp?: number;
238	  commandAuthorized?: boolean;
239	  bodyForAgent?: string;
240	  commandBody?: string;
241	  provider?: string;
242	  surface?: string;
243	  originatingChannel?: string;
244	  originatingTo?: string;
245	  extraContext?: Record<string, unknown>;
246	  deliver: (payload: OutboundReplyPayload) => Promise<void>;
247	  onRecordError: (err: unknown) => void;
248	  onDispatchError: (err: unknown, info: { kind: string }) => void;
249	}): Promise<{
250	  route: DirectDmRoute;
251	  storePath: string;
252	  ctxPayload: FinalizedMsgContext;
253	}> {
254	  const { route, buildEnvelope } = resolveInboundRouteEnvelopeBuilderWithRuntime({
255	    cfg: params.cfg,
256	    channel: params.channel,
257	    accountId: params.accountId,
258	    peer: params.peer,
259	    runtime: params.runtime.channel,
260	    sessionStore: params.cfg.session?.store,
261	  });
262	
263	  const { storePath, body } = buildEnvelope({
264	    channel: params.channelLabel,
265	    from: params.conversationLabel,
266	    body: params.rawBody,
267	    timestamp: params.timestamp,
268	  });
269	
270	  const ctxPayload = params.runtime.channel.reply.finalizeInboundContext({
271	    Body: body,
272	    BodyForAgent: params.bodyForAgent ?? params.rawBody,
273	    RawBody: params.rawBody,
274	    CommandBody: params.commandBody ?? params.rawBody,
275	    From: params.senderAddress,
276	    To: params.recipientAddress,
277	    SessionKey: route.sessionKey,
278	    AccountId: route.accountId ?? params.accountId,
279	    ChatType: "direct",
280	    ConversationLabel: params.conversationLabel,
281	    SenderId: params.senderId,
282	    Provider: params.provider ?? params.channel,
283	    Surface: params.surface ?? params.channel,
284	    MessageSid: params.messageId,
285	    MessageSidFull: params.messageId,
286	    Timestamp: params.timestamp,
287	    CommandAuthorized: params.commandAuthorized,
288	    OriginatingChannel: params.originatingChannel ?? params.channel,
289	    OriginatingTo: params.originatingTo ?? params.recipientAddress,
290	    ...params.extraContext,
291	  });
292	
293	  await recordInboundSessionAndDispatchReply({
294	    cfg: params.cfg,
295	    channel: params.channel,
296	    accountId: route.accountId ?? params.accountId,
297	    agentId: route.agentId,
298	    routeSessionKey: route.sessionKey,
299	    storePath,
300	    ctxPayload,
301	    recordInboundSession: params.runtime.channel.session.recordInboundSession,
302	    dispatchReplyWithBufferedBlockDispatcher:
303	      params.runtime.channel.reply.dispatchReplyWithBufferedBlockDispatcher,
304	    deliver: params.deliver,
305	    onRecordError: params.onRecordError,
306	    onDispatchError: params.onDispatchError,
307	  });
308	
309	  return {
310	    route,
311	    storePath,
312	    ctxPayload,
313	  };
314	}
