import { describeAccountSnapshot } from "openclaw/plugin-sdk/account-helpers";
import {
  createScopedDmSecurityResolver,
  createTopLevelChannelConfigAdapter,
} from "openclaw/plugin-sdk/channel-config-helpers";
import { createChannelPairingController } from "openclaw/plugin-sdk/channel-pairing";
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import {
  buildChannelConfigSchema,
  createChatChannelPlugin,
  DEFAULT_ACCOUNT_ID,
  formatPairingApproveHint,
} from "openclaw/plugin-sdk/core";
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import {
  createPreCryptoDirectDmAuthorizer,
  dispatchInboundDirectDmWithRuntime,
  resolveInboundDirectDmAccessWithRuntime,
} from "openclaw/plugin-sdk/direct-dm";
import {
  buildPassiveChannelStatusSummary,
  buildTrafficStatusSummary,
} from "openclaw/plugin-sdk/extension-shared";
import {
  collectStatusIssuesFromLastError,
  createComputedAccountStatusAdapter,
  createDefaultChannelRuntimeState,
} from "openclaw/plugin-sdk/status-helpers";
import { PulseboardConfigSchema } from "./config-schema.js";
import {
  normalizePulseboardTarget,
  normalizePulseboardAllowEntry,
  isBoardTarget,
  looksLikePulseboardTargetId,
} from "./normalize.js";
import { getPulseboardRuntime } from "./runtime.js";
import { sendPulseboardMessage } from "./send.js";
import { pulseboardSetupAdapter, pulseboardSetupWizard } from "./setup-surface.js";
import {
  listPulseboardAccountIds,
  resolveDefaultPulseboardAccountId,
  resolvePulseboardAccount,
  type ResolvedPulseboardAccount,
} from "./types.js";

function isPulseboardSenderAllowed(senderUsername: string, allowFrom: string[]): boolean {
  const normalizedSender = senderUsername.trim().toLowerCase();
  for (const entry of allowFrom) {
    const normalized = normalizePulseboardAllowEntry(entry);
    if (normalized === "*") {
      return true;
    }
    if (normalized === normalizedSender) {
      return true;
    }
  }
  return false;
}

async function resolvePulseboardDirectAccess(params: {
  cfg: Parameters<typeof resolveInboundDirectDmAccessWithRuntime>[0]["cfg"];
  accountId: string;
  dmPolicy: "pairing" | "allowlist" | "open" | "disabled";
  allowFrom: Array<string | number> | undefined;
  senderUsername: string;
  rawBody: string;
  runtime: Parameters<typeof resolveInboundDirectDmAccessWithRuntime>[0]["runtime"];
}) {
  return resolveInboundDirectDmAccessWithRuntime({
    cfg: params.cfg,
    channel: "pulseboard",
    accountId: params.accountId,
    dmPolicy: params.dmPolicy,
    allowFrom: params.allowFrom,
    senderId: params.senderUsername,
    rawBody: params.rawBody,
    isSenderAllowed: isPulseboardSenderAllowed,
    runtime: params.runtime,
    modeWhenAccessGroupsOff: "configured",
  });
}

const resolvePulseboardDmPolicy = createScopedDmSecurityResolver<ResolvedPulseboardAccount>({
  channelKey: "pulseboard",
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  defaultPolicy: "pairing",
  approveHint: formatPairingApproveHint("pulseboard"),
  normalizeEntry: (raw) => {
    const normalized = normalizePulseboardAllowEntry(raw);
    return normalized ?? raw.trim();
  },
});

const pulseboardConfigAdapter = createTopLevelChannelConfigAdapter<ResolvedPulseboardAccount>({
  sectionKey: "pulseboard",
  resolveAccount: (cfg) => resolvePulseboardAccount({ cfg }),
  listAccountIds: listPulseboardAccountIds,
  defaultAccountId: resolveDefaultPulseboardAccountId,
  deleteMode: "clear-fields",
  clearBaseFields: [
    "name",
    "defaultAccount",
    "apiToken",
    "serverUrl",
    "username",
    "boards",
    "dmPolicy",
    "groupPolicy",
    "allowFrom",
  ],
  resolveAllowFrom: (account) => account.config.allowFrom,
  formatAllowFrom: (allowFrom) =>
    allowFrom
      .map((entry) => String(entry).trim().toLowerCase())
      .filter(Boolean),
});

export const pulseboardPlugin: ChannelPlugin<ResolvedPulseboardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Real-time bulletin board messaging with named boards and DMs",
      order: 100,
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    configSchema: buildChannelConfigSchema(PulseboardConfigSchema),
    setup: pulseboardSetupAdapter,
    setupWizard: pulseboardSetupWizard,
    config: {
      ...pulseboardConfigAdapter,
      isConfigured: (account) => account.configured,
      describeAccount: (account) =>
        describeAccountSnapshot({
          account,
          configured: account.configured,
          extra: {
            serverUrl: account.serverUrl,
            username: account.username,
            boards: account.boards.join(", ") || "(none)",
          },
        }),
    },
    messaging: {
      normalizeTarget: (target) => normalizePulseboardTarget(target),
      targetResolver: {
        looksLikeId: (input) => looksLikePulseboardTargetId(input),
        hint: "<username|#board-name>",
      },
    },
    groups: {
      resolveRequireMention: () => true,
    },
    status: {
      ...createComputedAccountStatusAdapter<ResolvedPulseboardAccount>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        collectStatusIssues: (accounts) =>
          collectStatusIssuesFromLastError("pulseboard", accounts),
        buildChannelSummary: ({ snapshot }) =>
          buildPassiveChannelStatusSummary(snapshot, {
            serverUrl: snapshot.serverUrl ?? null,
            username: snapshot.username ?? null,
          }),
        resolveAccountSnapshot: ({ account, runtime }) => ({
          accountId: account.accountId,
          name: account.name,
          enabled: account.enabled,
          configured: account.configured,
          extra: {
            serverUrl: account.serverUrl,
            username: account.username,
            boards: account.boards,
            ...buildTrafficStatusSummary(runtime),
          },
        }),
      }),
    },
    gateway: {
      startAccount: async (ctx) => {
        const account = ctx.account;
        ctx.setStatus({
          accountId: account.accountId,
          serverUrl: account.serverUrl,
          username: account.username,
        });
        ctx.log?.info(
          `[${account.accountId}] starting PulseBoard provider (server: ${account.serverUrl}, user: ${account.username})`,
        );

        if (!account.configured) {
          throw new Error("PulseBoard API token not configured");
        }

        const runtime = getPulseboardRuntime();
        const pairing = createChannelPairingController({
          core: runtime,
          channel: "pulseboard",
          accountId: account.accountId,
        });

        const resolveInboundAccess = async (senderUsername: string, rawBody: string) =>
          await resolvePulseboardDirectAccess({
            cfg: ctx.cfg,
            accountId: account.accountId,
            dmPolicy: account.config.dmPolicy ?? "pairing",
            allowFrom: account.config.allowFrom,
            senderUsername,
            rawBody,
            runtime: {
              shouldComputeCommandAuthorized:
                runtime.channel.commands.shouldComputeCommandAuthorized,
              resolveCommandAuthorizedFromAuthorizers:
                runtime.channel.commands.resolveCommandAuthorizedFromAuthorizers,
            },
          });

        const authorizeSender = createPreCryptoDirectDmAuthorizer({
          resolveAccess: async (senderUsername) =>
            await resolveInboundAccess(senderUsername, ""),
          issuePairingChallenge: async ({ senderId, reply }) => {
            await pairing.issueChallenge({
              senderId,
              senderIdLine: `Your PulseBoard username: ${senderId}`,
              sendPairingReply: reply,
              onCreated: () => {
                ctx.log?.debug?.(
                  `[${account.accountId}] pulseboard pairing request sender=${senderId}`,
                );
              },
              onReplyError: (err) => {
                ctx.log?.warn?.(
                  `[${account.accountId}] pulseboard pairing reply failed for ${senderId}: ${String(err)}`,
                );
              },
            });
          },
          onBlocked: ({ senderId, reason }) => {
            ctx.log?.debug?.(
              `[${account.accountId}] blocked PulseBoard sender ${senderId} (${reason})`,
            );
          },
        });

        // Placeholder: in a real implementation this would open a WebSocket
        // connection to the PulseBoard server and listen for inbound messages.
        // The onMessage callback would call dispatchInboundDirectDmWithRuntime
        // for DMs and a group dispatch helper for board messages.
        ctx.log?.info(
          `[${account.accountId}] PulseBoard provider started (server: ${account.serverUrl}, boards: ${account.boards.join(", ") || "none"})`,
        );

        // Keep references so outbound can use them
        void authorizeSender;

        return {
          stop: () => {
            ctx.log?.info(`[${account.accountId}] PulseBoard provider stopped`);
          },
        };
      },
    },
  },
  pairing: {
    text: {
      idLabel: "pulseboardUsername",
      message: "Your pairing request has been approved!",
      normalizeAllowEntry: (entry) => {
        const normalized = normalizePulseboardAllowEntry(entry);
        return normalized ?? entry.trim();
      },
      notify: async ({ id, message }) => {
        // In a real implementation, send the approval message via PulseBoard DM
        void id;
        void message;
      },
    },
  },
  security: {
    resolveDmPolicy: resolvePulseboardDmPolicy,
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ cfg, to, text, accountId }) => {
      const core = getPulseboardRuntime();
      const aid = accountId ?? DEFAULT_ACCOUNT_ID;
      const account = resolvePulseboardAccount({ cfg, accountId: aid });

      if (!account.configured) {
        throw new Error(`PulseBoard not configured for account ${aid}`);
      }

      const tableMode = core.channel.text.resolveMarkdownTableMode({
        cfg,
        channel: "pulseboard",
        accountId: aid,
      });
      const message = core.channel.text.convertMarkdownTables(text ?? "", tableMode);
      const normalizedTo = normalizePulseboardTarget(to);

      const result = await sendPulseboardMessage({
        serverUrl: account.serverUrl,
        apiToken: account.apiToken,
        to: normalizedTo,
        text: message,
      });

      return attachChannelToResult("pulseboard", {
        to: normalizedTo,
        messageId: result.messageId,
      });
    },
  },
});

